/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltElyrsQyList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE */ elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr, gios_cd, elcpwstn_div_cd FROM ( SELECT /*+ LEADING(B A) */ A.elcpwstn_cd, A.elcpwstn_nm, A.hq_cd, A.sap_bplc_vu, A.elcpwstn_cls_cd, A.dsply_ordr, B.gios_cd, B.elcpwstn_div_cd FROM ( SELECT elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE elcpwstn_cls_cd IN ('0001', '0002', '0003', '0007') ) A, ( SELECT DISTINCT usr_dfn_vu1 AS elcpwstn_cd, usr_dfn_vu2 AS gios_cd, usr_dfn_vu3 AS elcpwstn_div_cd FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' ) B WHERE A.elcpwstn_cd = B.elcpwstn_cd(+) AND B.gios_cd IS NOT NULL AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND A.elcpwstn_cd = #{ecsElcpwstnDivCd}
) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr, gios_cd, elcpwstn_div_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt, dsply_ordr ) SELECT
sty || '년' AS ymd,
std || '일' AS ymd,
ROUND(mon01, 0) AS mon01, ROUND(mon02, 0) AS mon02, ROUND(mon03, 0) AS mon03, ROUND(mon04, 0) AS mon04, ROUND(mon05, 0) AS mon05, ROUND(mon06, 0) AS mon06, ROUND(mon07, 0) AS mon07, ROUND(mon08, 0) AS mon08, ROUND(mon09, 0) AS mon09, ROUND(mon10, 0) AS mon10, ROUND(mon11, 0) AS mon11, ROUND(mon12, 0) AS mon12, ROUND(( NVL(mon01, 0) + NVL(mon02, 0) + NVL(mon03, 0) + NVL(mon04, 0) + NVL(mon05, 0) + NVL(mon06, 0) + NVL(mon07, 0) + NVL(mon08, 0) + NVL(mon09, 0) + NVL(mon10, 0) + NVL(mon11, 0) + NVL(mon12, 0) ), 0) AS total FROM ( SELECT
SUBSTR(dt, 0, 4) AS sty,
SUBSTR(dt, 7, 2) AS std,
SUBSTR(dt, 5, 2) AS stm, NVL(SUM(elyrs_de_acmtl_qy), 0) AS elyrs_de_acmtl_qy FROM ( SELECT /*+ LEADING(DATE_MAPPING_LIST A) */ DATE_MAPPING_LIST.dt, DATE_MAPPING_LIST.elcpwstn_nm, DATE_MAPPING_LIST.hq_cd, CASE WHEN A.elyrs_de_acmtl_qy < 0 THEN 0 ELSE A.elyrs_de_acmtl_qy END AS elyrs_de_acmtl_qy FROM DATE_MAPPING_LIST, ( SELECT stdr_de, dam_cd, elcpwstn_div_cd, SUM(elyrs_de_acmtl_qy) AS elyrs_de_acmtl_qy FROM WRO.tm_eg03114 WHERE
stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) GROUP BY stdr_de, dam_cd, elcpwstn_div_cd
) A WHERE DATE_MAPPING_LIST.gios_cd = A.dam_cd(+) AND DATE_MAPPING_LIST.elcpwstn_div_cd = A.elcpwstn_div_cd(+) AND DATE_MAPPING_LIST.dt = A.stdr_de(+) ) GROUP BY
SUBSTR(dt, 0, 4),
SUBSTR(dt, 7, 2),
SUBSTR(dt, 5, 2) ) PIVOT ( MAX(elyrs_de_acmtl_qy) FOR stm IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12 ) ) ORDER BY
sty
std

/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltEpwrDelngQyList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE */ A.elcpwstn_cd, A.elcpwstn_nm, A.hq_cd, A.elcpwstn_cls_cd, A.dsply_ordr, B.gios_cd, B.elcpwstn_div_cd FROM ( SELECT elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE /* centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' */ elcpwstn_div_cd != 'X' AND accnut_lnk_elcpwstn_yn = 'Y' AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND elcpwstn_cd = #{ecsElcpwstnDivCd}
) A, ( SELECT DISTINCT usr_dfn_vu1 AS elcpwstn_cd, usr_dfn_vu2 AS gios_cd, usr_dfn_vu3 AS elcpwstn_div_cd FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' ) B WHERE A.elcpwstn_cd = B.elcpwstn_cd(+) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd, elcpwstn_nm, hq_cd, elcpwstn_cls_cd, gios_cd, elcpwstn_div_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt, dsply_ordr ), OLD_DATA_LIST AS ( SELECT stdr_de, dam_cd, elcpwstn_div_cd, pwrtrn_de_acmtl_qy FROM WRO.tm_eg03114 WHERE dam_cd IN ('CJ') AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) SELECT
sty || '년' AS ymd,
std || '일' AS ymd,
ROUND(mon01, 0) AS mon01, ROUND(mon02, 0) AS mon02, ROUND(mon03, 0) AS mon03, ROUND(mon04, 0) AS mon04, ROUND(mon05, 0) AS mon05, ROUND(mon06, 0) AS mon06, ROUND(mon07, 0) AS mon07, ROUND(mon08, 0) AS mon08, ROUND(mon09, 0) AS mon09, ROUND(mon10, 0) AS mon10, ROUND(mon11, 0) AS mon11, ROUND(mon12, 0) AS mon12, ROUND(( NVL(mon01, 0) + NVL(mon02, 0) + NVL(mon03, 0) + NVL(mon04, 0) + NVL(mon05, 0) + NVL(mon06, 0) + NVL(mon07, 0) + NVL(mon08, 0) + NVL(mon09, 0) + NVL(mon10, 0) + NVL(mon11, 0) + NVL(mon12, 0) ), 0) AS total FROM ( SELECT /*+ LEADING(DATE_MAPPING_LIST A) */
SUBSTR(dt, 0, 4) AS sty,
SUBSTR(dt, 7, 2) AS std,
SUBSTR(dt, 5, 2) AS stm, SUM(CASE WHEN dt < '20230118' AND elcpwstn_cd IN ('1080', 'BG75') THEN pwrtrn_de_acmtl_qy ELSE elyrs_qy END) AS excclc_sum_amt FROM ( SELECT DATE_MAPPING_LIST.dt, DATE_MAPPING_LIST.elcpwstn_cd, NVL(A.elyrs_qy / 1000, 0) AS elyrs_qy, CASE WHEN DATE_MAPPING_LIST.dt < '20230118' AND DATE_MAPPING_LIST.elcpwstn_cd = '1080' THEN NVL(OLD_DATA_LIST.pwrtrn_de_acmtl_qy, 0) - ( SELECT NVL(A.pwrtrn_de_acmtl_qy, 0) FROM OLD_DATA_LIST A WHERE A.stdr_de = DATE_MAPPING_LIST.dt AND A.dam_cd = DATE_MAPPING_LIST.gios_cd AND A.elcpwstn_div_cd = '2' ) WHEN DATE_MAPPING_LIST.dt < '20230118' AND DATE_MAPPING_LIST.elcpwstn_cd = 'BG75' THEN NVL(OLD_DATA_LIST.pwrtrn_de_acmtl_qy, 0) ELSE NULL END AS pwrtrn_de_acmtl_qy FROM DATE_MAPPING_LIST, ( SELECT stdr_de, elcpwstn_cd, elyrs_qy FROM WRO.tm_eg04105 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) A, OLD_DATA_LIST WHERE A.elcpwstn_cd(+) = DATE_MAPPING_LIST.elcpwstn_cd AND A.stdr_de(+) = DATE_MAPPING_LIST.dt AND OLD_DATA_LIST.dam_cd(+) = DATE_MAPPING_LIST.gios_cd AND OLD_DATA_LIST.elcpwstn_div_cd(+) = DATE_MAPPING_LIST.elcpwstn_div_cd AND OLD_DATA_LIST.stdr_de(+) = DATE_MAPPING_LIST.dt ) GROUP BY
SUBSTR(dt, 0, 4),
SUBSTR(dt, 7, 2),
SUBSTR(dt, 5, 2) ) PIVOT ( MAX(excclc_sum_amt) FOR stm IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12 ) ) ORDER BY
sty
std

/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltInhouseCnstqyList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE */ A.elcpwstn_cd, A.elcpwstn_nm, A.hq_cd, A.elcpwstn_cls_cd, A.dsply_ordr, B.gios_cd, B.elcpwstn_div_cd FROM ( SELECT elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE elcpwstn_cls_cd IN ('0001', '0002', '0007') AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND elcpwstn_cd = #{ecsElcpwstnDivCd}
) A, ( SELECT DISTINCT usr_dfn_vu1 AS elcpwstn_cd, usr_dfn_vu2 AS gios_cd, usr_dfn_vu3 AS elcpwstn_div_cd FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' ) B WHERE A.elcpwstn_cd = B.elcpwstn_cd(+) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd, elcpwstn_nm, hq_cd, elcpwstn_cls_cd, gios_cd, elcpwstn_div_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt, dsply_ordr ), OLD_DATA_LIST AS ( SELECT stdr_de, dam_cd, elcpwstn_div_cd, pwrtrn_de_acmtl_qy FROM WRO.tm_eg03114 WHERE dam_cd IN ('CJ') AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) SELECT
sty || '년' AS ymd,
std || '일' AS ymd,
ROUND(mon01, 0) AS mon01, ROUND(mon02, 0) AS mon02, ROUND(mon03, 0) AS mon03, ROUND(mon04, 0) AS mon04, ROUND(mon05, 0) AS mon05, ROUND(mon06, 0) AS mon06, ROUND(mon07, 0) AS mon07, ROUND(mon08, 0) AS mon08, ROUND(mon09, 0) AS mon09, ROUND(mon10, 0) AS mon10, ROUND(mon11, 0) AS mon11, ROUND(mon12, 0) AS mon12, ROUND(( NVL(mon01, 0) + NVL(mon02, 0) + NVL(mon03, 0) + NVL(mon04, 0) + NVL(mon05, 0) + NVL(mon06, 0) + NVL(mon07, 0) + NVL(mon08, 0) + NVL(mon09, 0) + NVL(mon10, 0) + NVL(mon11, 0) + NVL(mon12, 0) ), 0) AS total FROM ( SELECT
SUBSTR(dt, 0, 4) AS sty,
SUBSTR(dt, 7, 2) AS std,
SUBSTR(dt, 5, 2) AS stm, NVL(SUM(elyrs_de_acmtl_qy - elyrs_qy), 0) AS inhouse_cnstqy FROM ( SELECT /*+ LEADING(DATE_MAPPING_LIST A B) */ DATE_MAPPING_LIST.dt, DATE_MAPPING_LIST.elcpwstn_nm, DATE_MAPPING_LIST.hq_cd, CASE WHEN A.elyrs_de_acmtl_qy < 0 THEN 0 ELSE A.elyrs_de_acmtl_qy END AS elyrs_de_acmtl_qy, CASE WHEN A.elyrs_de_acmtl_qy < 0 THEN 0 ELSE B.elyrs_qy END AS elyrs_qy FROM DATE_MAPPING_LIST, ( SELECT stdr_de, dam_cd, elcpwstn_div_cd, elyrs_de_acmtl_qy, pwrtrn_de_acmtl_qy FROM WRO.tm_eg03114 WHERE stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) A, ( SELECT dt AS stdr_de, elcpwstn_cd, CASE WHEN dt < '20230118' AND elcpwstn_cd IN ('1080', 'BG75') THEN pwrtrn_de_acmtl_qy ELSE elyrs_qy END AS elyrs_qy FROM ( SELECT DATE_MAPPING_LIST.dt, DATE_MAPPING_LIST.elcpwstn_cd, NVL(A.elyrs_qy / 1000, 0) AS elyrs_qy, CASE WHEN DATE_MAPPING_LIST.dt < '20230118' AND DATE_MAPPING_LIST.elcpwstn_cd = '1080' THEN NVL(OLD_DATA_LIST.pwrtrn_de_acmtl_qy, 0) - ( SELECT NVL(A.pwrtrn_de_acmtl_qy, 0) FROM OLD_DATA_LIST A WHERE A.stdr_de = DATE_MAPPING_LIST.dt AND A.dam_cd = DATE_MAPPING_LIST.gios_cd AND A.elcpwstn_div_cd = '2' ) WHEN DATE_MAPPING_LIST.dt < '20230118' AND DATE_MAPPING_LIST.elcpwstn_cd = 'BG75' THEN NVL(OLD_DATA_LIST.pwrtrn_de_acmtl_qy, 0) ELSE NULL END AS pwrtrn_de_acmtl_qy FROM DATE_MAPPING_LIST, ( SELECT stdr_de, elcpwstn_cd, elyrs_qy FROM WRO.tm_eg04105 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) A, OLD_DATA_LIST WHERE A.elcpwstn_cd(+) = DATE_MAPPING_LIST.elcpwstn_cd AND A.stdr_de(+) = DATE_MAPPING_LIST.dt AND OLD_DATA_LIST.dam_cd(+) = DATE_MAPPING_LIST.gios_cd AND OLD_DATA_LIST.elcpwstn_div_cd(+) = DATE_MAPPING_LIST.elcpwstn_div_cd AND OLD_DATA_LIST.stdr_de(+) = DATE_MAPPING_LIST.dt ) ) B WHERE DATE_MAPPING_LIST.gios_cd = A.dam_cd(+) AND DATE_MAPPING_LIST.elcpwstn_div_cd = A.elcpwstn_div_cd(+) AND DATE_MAPPING_LIST.elcpwstn_cd = B.elcpwstn_cd(+) AND DATE_MAPPING_LIST.dt = A.stdr_de(+) AND DATE_MAPPING_LIST.dt = B.stdr_de(+) ) GROUP BY
SUBSTR(dt, 0, 4),
SUBSTR(dt, 7, 2),
SUBSTR(dt, 5, 2) ) PIVOT ( MAX(inhouse_cnstqy) FOR stm IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12 ) ) ORDER BY
sty
std

/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltElyrsErnList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(B A) */ elcpwstn_cd FROM ( SELECT elcpwstn_cd FROM WRO.tc_eg10101 WHERE /* centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' */ elcpwstn_div_cd != 'X' AND accnut_lnk_elcpwstn_yn = 'Y' AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND elcpwstn_cd = #{ecsElcpwstnDivCd}
) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt ) SELECT
sty || '년' AS ymd,
std || '일' AS ymd,
ROUND(mon01, 0) AS mon01, ROUND(mon02, 0) AS mon02, ROUND(mon03, 0) AS mon03, ROUND(mon04, 0) AS mon04, ROUND(mon05, 0) AS mon05, ROUND(mon06, 0) AS mon06, ROUND(mon07, 0) AS mon07, ROUND(mon08, 0) AS mon08, ROUND(mon09, 0) AS mon09, ROUND(mon10, 0) AS mon10, ROUND(mon11, 0) AS mon11, ROUND(mon12, 0) AS mon12, ROUND(( NVL(mon01, 0) + NVL(mon02, 0) + NVL(mon03, 0) + NVL(mon04, 0) + NVL(mon05, 0) + NVL(mon06, 0) + NVL(mon07, 0) + NVL(mon08, 0) + NVL(mon09, 0) + NVL(mon10, 0) + NVL(mon11, 0) + NVL(mon12, 0) ), 0) AS total FROM ( SELECT /*+ LEADING(DATE_MAPPING_LIST A) */
SUBSTR(DATE_MAPPING_LIST.dt, 0, 4) AS sty,
SUBSTR(DATE_MAPPING_LIST.dt, 7, 2) AS std,
SUBSTR(DATE_MAPPING_LIST.dt, 5, 2) AS stm, SUM(NVL(A.excclc_sum_amt, 0)) AS excclc_sum_amt FROM ( SELECT stdr_de, elcpwstn_cd, excclc_sum_amt FROM WRO.tm_eg03121 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) A, DATE_MAPPING_LIST WHERE A.elcpwstn_cd(+) = DATE_MAPPING_LIST.elcpwstn_cd AND A.stdr_de(+) = DATE_MAPPING_LIST.dt GROUP BY
SUBSTR(DATE_MAPPING_LIST.dt, 0, 4),
SUBSTR(DATE_MAPPING_LIST.dt, 7, 2),
