/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltElyrsUpcList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(B A) */ elcpwstn_cd FROM ( SELECT elcpwstn_cd FROM WRO.tc_eg10101 WHERE /* centr_elyrs_yn IN ('Y', 'N', 'X') AND accnut_acnt_cd LIKE '' || '%' */ elcpwstn_div_cd != 'X' AND accnut_lnk_elcpwstn_yn = 'Y' AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND elcpwstn_cd = #{ecsElcpwstnDivCd}
) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt ), DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(A B) */ A.stdr_de, A.elcpwstn_cd, A.elyrs_upc_vu, A.elyrs_qy, B.excclc_sum_amt FROM ( SELECT stdr_de, elcpwstn_cd, NVL((ROUND(elyrs_upc_vu * 100) * 0.01), 0) AS elyrs_upc_vu, NVL(elyrs_qy / 1000, 0) AS elyrs_qy FROM WRO.tm_eg04105 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) A, ( SELECT stdr_de, elcpwstn_cd, NVL(excclc_sum_amt, 0) AS excclc_sum_amt FROM WRO.tm_eg03121 WHERE excclc_div_cd = '0001' AND stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) ) B WHERE A.elcpwstn_cd = B.elcpwstn_cd AND A.stdr_de = B.stdr_de ), DATA_LIST AS ( SELECT /*+ LEADING(DATE_MAPPING_LIST DATA_INIT_LIST) */
SUBSTR(DATE_MAPPING_LIST.dt, 0, 4) AS sty,
SUBSTR(DATE_MAPPING_LIST.dt, 7, 2) AS std,
SUBSTR(DATE_MAPPING_LIST.dt, 5, 2) AS stm, ROUND(NVL(ROUND(SUM(DATA_INIT_LIST.excclc_sum_amt)) / NULLIF(ROUND(SUM(DATA_INIT_LIST.elyrs_qy), 3), 0), 0), 2) AS excclc_sum_amt
FROM DATA_INIT_LIST, DATE_MAPPING_LIST WHERE DATA_INIT_LIST.elcpwstn_cd(+) = DATE_MAPPING_LIST.elcpwstn_cd AND DATA_INIT_LIST.stdr_de(+) = DATE_MAPPING_LIST.dt GROUP BY
SUBSTR(DATE_MAPPING_LIST.dt, 0, 4),
SUBSTR(DATE_MAPPING_LIST.dt, 7, 2),
SUBSTR(DATE_MAPPING_LIST.dt, 5, 2)
UNION ALL SELECT SUBSTR(sty, 0, 4) AS sty, 'total' AS stm, ROUND(NVL(ROUND(SUM(excclc_sum_amt)) / NULLIF(ROUND(SUM(elyrs_qy), 3), 0), 0), 2) AS excclc_sum_amt
FROM ( SELECT /*+ LEADING(DATE_MAPPING_LIST DATA_INIT_LIST) */ SUBSTR(DATE_MAPPING_LIST.dt, 0, 4) AS sty, SUBSTR(DATE_MAPPING_LIST.dt, 5, 2) AS stm, SUM(DATA_INIT_LIST.elyrs_upc_vu) AS elyrs_upc_vu,
SUM(DATA_INIT_LIST.excclc_sum_amt) AS excclc_sum_amt, SUM(DATA_INIT_LIST.elyrs_qy) AS elyrs_qy FROM DATA_INIT_LIST, DATE_MAPPING_LIST WHERE DATA_INIT_LIST.elcpwstn_cd(+) = DATE_MAPPING_LIST.elcpwstn_cd AND DATA_INIT_LIST.stdr_de(+) = DATE_MAPPING_LIST.dt GROUP BY SUBSTR(DATE_MAPPING_LIST.dt, 0, 4), SUBSTR(DATE_MAPPING_LIST.dt, 5, 2) ) GROUP BY SUBSTR(sty, 0, 4)
) SELECT
sty || '년' AS ymd,
std || '일' AS ymd,
ROUND(mon01, 2) AS mon01, ROUND(mon02, 2) AS mon02, ROUND(mon03, 2) AS mon03, ROUND(mon04, 2) AS mon04, ROUND(mon05, 2) AS mon05, ROUND(mon06, 2) AS mon06, ROUND(mon07, 2) AS mon07, ROUND(mon08, 2) AS mon08, ROUND(mon09, 2) AS mon09, ROUND(mon10, 2) AS mon10, ROUND(mon11, 2) AS mon11, ROUND(mon12, 2) AS mon12, ROUND(total, 2) AS total FROM DATA_LIST PIVOT ( MAX(excclc_sum_amt) FOR stm IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12, 'total' AS total ) ) ORDER BY
sty
std

/* PRDCTN_ACMSLT_Dao_retrievePrdctnAcmsltOrtoList */ WITH DATE_LIST AS ( SELECT /*+ MATERIALZE */ TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') AS dt FROM DUAL CONNECT BY TO_CHAR(TO_DATE(SUBSTR(#{strtDt}, 0, 4) || '0101', 'yyyyMMdd') + LEVEL - 1, 'yyyyMMdd') <= SUBSTR(#{endDt}, 0, 4) || '1231' ), MAPPING_LIST AS ( SELECT /*+ MATERIALZE */ elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr, gios_cd, elcpwstn_div_cd FROM ( SELECT /*+ LEADING(B A) */ A.elcpwstn_cd, A.elcpwstn_nm, A.hq_cd, A.sap_bplc_vu, A.elcpwstn_cls_cd, A.dsply_ordr, B.gios_cd, B.elcpwstn_div_cd FROM ( SELECT elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr FROM WRO.tc_eg10101 WHERE elcpwstn_cls_cd IN ('0001', '0002', '0007') ) A, ( SELECT DISTINCT usr_dfn_vu1 AS elcpwstn_cd, usr_dfn_vu2 AS gios_cd, usr_dfn_vu3 AS elcpwstn_div_cd FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' ) B WHERE A.elcpwstn_cd = B.elcpwstn_cd(+) AND IN ( SELECT objid FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsBasinDivCd}
) AND elcpwstn_cls_cd IN ( SELECT DISTINCT REGEXP_SUBSTR(elcpwstn_cls_cd, '[^,]+', 1, LEVEL) AS elcpwstn_cls_cd FROM ( SELECT elcpwstn_cls_cd FROM (
) WHERE 1 = 1
AND cmmn_cd = #{ecsSetcscDivCd}
) CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(elcpwstn_cls_cd, '[^,]+', '')) + 1 )
AND A.elcpwstn_cd = #{ecsElcpwstnDivCd}
) ), DATE_MAPPING_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_LIST MAPPING_LIST) */ dt, elcpwstn_cd, elcpwstn_nm, hq_cd, sap_bplc_vu, elcpwstn_cls_cd, dsply_ordr, gios_cd, elcpwstn_div_cd FROM DATE_LIST, MAPPING_LIST ORDER BY dt, dsply_ordr ), DATA_INIT_LIST AS ( SELECT /*+ MATERIALZE LEADING(DATE_MAPPING_LIST A) */ DATE_MAPPING_LIST.dt, DATE_MAPPING_LIST.elcpwstn_nm, DATE_MAPPING_LIST.hq_cd, TO_CHAR(LAST_DAY(DATE_MAPPING_LIST.dt), 'dd') AS dcnt, A.hr01_mesure_vu, A.min01_mesure_vu FROM DATE_MAPPING_LIST, ( SELECT stdr_de, TRIM(dam_cd) AS dam_cd, NVL(SUM(hr01_mesure_vu), 0) AS hr01_mesure_vu, NVL(SUM(min01_mesure_vu), 0) AS min01_mesure_vu FROM WRO.tm_eg05103 WHERE stdr_de BETWEEN ( SELECT MIN(dt) FROM DATE_MAPPING_LIST ) AND ( SELECT MAX(dt) FROM DATE_MAPPING_LIST ) AND TRIM(dam_cd) IN ( SELECT usr_dfn_vu2 FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' AND cmmn_cd LIKE '_' || ( SELECT cmmn_cd FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1001' AND cmmn_cd_nm = '대수력' ) || '%' ) GROUP BY stdr_de, dam_cd ) A WHERE DATE_MAPPING_LIST.gios_cd = A.dam_cd(+) AND DATE_MAPPING_LIST.dt = A.stdr_de(+) ), DATA_LIST AS ( SELECT /*+ MATERIALZE */ std, stm, ROUND((NVL(SUM(hr01_mesure_vu), 0) + NVL(SUM(min01_mesure_vu), 0)) / (24 * 60 * 1) * 100, 2) AS orto FROM ( SELECT SUBSTR(dt, 7, 2) AS std, SUBSTR(dt, 5, 2) AS stm, MAX(dcnt) AS dcnt, NVL(SUM(hr01_mesure_vu), 0) * 60 AS hr01_mesure_vu, NVL(SUM(min01_mesure_vu), 0) AS min01_mesure_vu FROM DATA_INIT_LIST GROUP BY SUBSTR(dt, 7, 2), SUBSTR(dt, 5, 2) ) GROUP BY std, stm ) SELECT std || '일' AS ymd, ROUND(NVL(mon01, 0), 2) AS mon01, ROUND(NVL(mon02, 0), 2) AS mon02, ROUND(NVL(mon03, 0), 2) AS mon03, ROUND(NVL(mon04, 0), 2) AS mon04, ROUND(NVL(mon05, 0), 2) AS mon05, ROUND(NVL(mon06, 0), 2) AS mon06, ROUND(NVL(mon07, 0), 2) AS mon07, ROUND(NVL(mon08, 0), 2) AS mon08, ROUND(NVL(mon09, 0), 2) AS mon09, ROUND(NVL(mon10, 0), 2) AS mon10, ROUND(NVL(mon11, 0), 2) AS mon11, ROUND(NVL(mon12, 0), 2) AS mon12 FROM DATA_LIST PIVOT ( MAX(orto) FOR stm IN ( '01' AS mon01, '02' AS mon02, '03' AS mon03, '04' AS mon04, '05' AS mon05, '06' AS mon06, '07' AS mon07, '08' AS mon08, '09' AS mon09, '10' AS mon10, '11' AS mon11, '12' AS mon12 ) ) ORDER BY std
